import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Adapting the Interface, Not the Model: Runtime Harness Adaptation for Deterministic LLM Agents","description":"","frontmatter":{"title":"Adapting the Interface, Not the Model: Runtime Harness Adaptation for Deterministic LLM Agents","arxiv_id":2605.22166,"authors":"Tianshi Xu, Huifeng Wen, Meng Li","fetched":"2026-05-23T00:00:00.000Z","published":"2026-05-21T00:00:00.000Z","source":"https://arxiv.org/abs/2605.22166","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-05-21-adapting-interface-not-model-life-harness-2605-22166.md","filePath":"research/papers/2026-05-21-adapting-interface-not-model-life-harness-2605-22166.md","lastUpdated":1779901665000}'),i={name:"research/papers/2026-05-21-adapting-interface-not-model-life-harness-2605-22166.md"};function s(o,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="adapting-the-interface-not-the-model-runtime-harness-adaptation-for-deterministic-llm-agents" tabindex="-1">Adapting the Interface, Not the Model: Runtime Harness Adaptation for Deterministic LLM Agents <a class="header-anchor" href="#adapting-the-interface-not-the-model-runtime-harness-adaptation-for-deterministic-llm-agents" aria-label="Permalink to &quot;Adapting the Interface, Not the Model: Runtime Harness Adaptation for Deterministic LLM Agents&quot;">​</a></h1><p><strong>Authors</strong>: Tianshi Xu, Huifeng Wen, Meng Li (Peking University) <strong>Published</strong>: May 21, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.22166" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.22166</a><strong>arXiv ID</strong>: 2605.22166 <strong>Categories</strong>: cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Rather than updating model weights, this paper proposes <strong>Life-Harness</strong>, a runtime adaptation framework that evolves &quot;the runtime layer that mediates how a frozen model observes the environment, uses tools, realizes actions, interprets feedback, and recovers from degenerate trajectories.&quot; The approach achieves an average relative improvement of <strong>88.5%</strong> across seven deterministic environments with 18 model backbones.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>The paper&#39;s central claim: <strong>adapting the harness interface is more efficient and generalizable than adapting the model itself</strong> for deterministic agent environments. Life-Harness addresses recurring failure modes without any weight updates, fine-tuning, or training data collection.</p><p>Key distinction from prior harness optimization work (Meta-Harness, autoresearch): those methods treat harnesses as searchable code artifacts. Life-Harness treats them as &quot;structured runtime interfaces&quot; enabling reproducible failure diagnosis and reusable interventions.</p><hr><h2 id="_1-four-failure-categories" tabindex="-1">1. Four Failure Categories <a class="header-anchor" href="#_1-four-failure-categories" aria-label="Permalink to &quot;1. Four Failure Categories&quot;">​</a></h2><p>Life-Harness identifies and addresses four recurring failure categories in deterministic agent environments:</p><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th>Example Manifestation</th></tr></thead><tbody><tr><td><strong>Action realization failures</strong></td><td>Malformed outputs that cannot be executed</td><td>Wrong JSON schema, undefined tool names</td></tr><tr><td><strong>Environment contract mismatches</strong></td><td>Incorrect tool usage violating API contracts</td><td>Missing required parameters, invalid sequence</td></tr><tr><td><strong>Trajectory degeneration</strong></td><td>Repetition, stagnation, circular loops</td><td>Calling same tool repeatedly without progress</td></tr><tr><td><strong>Residual reasoning failures</strong></td><td>Computation errors in arithmetic or logic</td><td>Off-by-one errors, incorrect string operations</td></tr></tbody></table><hr><h2 id="_2-four-lifecycle-layers" tabindex="-1">2. Four Lifecycle Layers <a class="header-anchor" href="#_2-four-lifecycle-layers" aria-label="Permalink to &quot;2. Four Lifecycle Layers&quot;">​</a></h2><p>Life-Harness operates through four layers at different interaction stages:</p><h3 id="layer-1-environment-contract-layer" tabindex="-1">Layer 1: Environment Contract Layer <a class="header-anchor" href="#layer-1-environment-contract-layer" aria-label="Permalink to &quot;Layer 1: Environment Contract Layer&quot;">​</a></h3><p><strong>Stage</strong>: Pre-interaction<br><strong>Function</strong>: Clarifies tool descriptions and interface constraints before the model makes any calls<br><strong>Mechanism</strong>: Augments system context with explicit contract statements about tool usage, parameter types, and sequencing constraints<br><strong>Addresses</strong>: Environment contract mismatches</p><h3 id="layer-2-procedural-skill-layer" tabindex="-1">Layer 2: Procedural Skill Layer <a class="header-anchor" href="#layer-2-procedural-skill-layer" aria-label="Permalink to &quot;Layer 2: Procedural Skill Layer&quot;">​</a></h3><p><strong>Stage</strong>: Pre-interaction<br><strong>Function</strong>: Retrieves task-relevant procedures from training trajectories using BM25 similarity search<br><strong>Mechanism</strong>: Indexes past successful trajectories; at task initialization, retrieves top-k similar procedures and injects as few-shot context<br><strong>Addresses</strong>: Residual reasoning failures</p><h3 id="layer-3-action-realization-layer" tabindex="-1">Layer 3: Action Realization Layer <a class="header-anchor" href="#layer-3-action-realization-layer" aria-label="Permalink to &quot;Layer 3: Action Realization Layer&quot;">​</a></h3><p><strong>Stage</strong>: Pre-execution (before each tool call)<br><strong>Function</strong>: Validates model actions before execution; canonicalizes interface errors<br><strong>Mechanism</strong>: Parses proposed action against tool schema; if malformed, attempts canonical repair (e.g., type coercion, missing-field defaults); rejects if irreparable<br><strong>Addresses</strong>: Action realization failures</p><h3 id="layer-4-trajectory-regulation-layer" tabindex="-1">Layer 4: Trajectory Regulation Layer <a class="header-anchor" href="#layer-4-trajectory-regulation-layer" aria-label="Permalink to &quot;Layer 4: Trajectory Regulation Layer&quot;">​</a></h3><p><strong>Stage</strong>: Post-execution (after each tool call)<br><strong>Function</strong>: Monitors patterns, detects and prevents trajectory degeneration<br><strong>Mechanism</strong>: Sliding-window analysis of recent actions; detects repetition patterns, stagnation indicators; injects recovery interventions or terminates degenerate trajectories<br><strong>Addresses</strong>: Trajectory degeneration</p><hr><h2 id="_3-experimental-results" tabindex="-1">3. Experimental Results <a class="header-anchor" href="#_3-experimental-results" aria-label="Permalink to &quot;3. Experimental Results&quot;">​</a></h2><h3 id="evaluation-setup" tabindex="-1">Evaluation Setup <a class="header-anchor" href="#evaluation-setup" aria-label="Permalink to &quot;Evaluation Setup&quot;">​</a></h3><ul><li><strong>Environments</strong>: Seven deterministic environments spanning τ-bench, τ²-bench, AgentBench</li><li><strong>Model backbones</strong>: 18 diverse models</li><li><strong>Harness source</strong>: Life-Harness components evolved using Qwen3-4B-Instruct as the development model</li></ul><h3 id="main-results" tabindex="-1">Main Results <a class="header-anchor" href="#main-results" aria-label="Permalink to &quot;Main Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Settings improved</td><td>116 out of 126 (model × environment)</td></tr><tr><td>Average relative improvement</td><td><strong>88.5%</strong></td></tr><tr><td>Transfer: Qwen3-4B-Instruct → 17 other models</td><td>Successful</td></tr><tr><td>Complementarity with specialized tool-use models</td><td>Further improved</td></tr></tbody></table><h3 id="transfer-analysis" tabindex="-1">Transfer Analysis <a class="header-anchor" href="#transfer-analysis" aria-label="Permalink to &quot;Transfer Analysis&quot;">​</a></h3><p>Harnesses evolved on a small model (Qwen3-4B-Instruct) transferred successfully to 17 other models, including larger and more capable models. This demonstrates that failure patterns are environment-level phenomena, not model-level idiosyncrasies.</p><h3 id="complementarity" tabindex="-1">Complementarity <a class="header-anchor" href="#complementarity" aria-label="Permalink to &quot;Complementarity&quot;">​</a></h3><p>Life-Harness is complementary to model training. Specialized tool-use models (already trained on tool use) achieved further gains with Life-Harness applied, suggesting harness adaptation and model training improve different aspects of agent behavior.</p><hr><h2 id="_4-comparison-to-prior-harness-optimization-work" tabindex="-1">4. Comparison to Prior Harness Optimization Work <a class="header-anchor" href="#_4-comparison-to-prior-harness-optimization-work" aria-label="Permalink to &quot;4. Comparison to Prior Harness Optimization Work&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Harness Treated As</th><th>Adaptation Target</th><th>Key Limitation Addressed</th></tr></thead><tbody><tr><td>Meta-Harness (2603.28052)</td><td>Searchable code artifact</td><td>Code components via LLM proposer</td><td>Manual harness engineering</td></tr><tr><td>The Last Harness (2604.21003)</td><td>Evolution blueprint</td><td>Full harness via adversarial eval</td><td>Single-task optimization</td></tr><tr><td>Life-Harness (this paper)</td><td>Structured runtime interface</td><td>Lifecycle layers for failure modes</td><td>Failure diagnosis reproducibility</td></tr></tbody></table><p>Life-Harness is unique in that its structure maps directly onto <strong>failure taxonomy</strong>, enabling interpretable attribution: each improvement can be traced to the specific lifecycle layer that addressed the specific failure category.</p><hr><h2 id="_5-implications-for-harness-design" tabindex="-1">5. Implications for Harness Design <a class="header-anchor" href="#_5-implications-for-harness-design" aria-label="Permalink to &quot;5. Implications for Harness Design&quot;">​</a></h2><ol><li><p><strong>Failure-first design</strong>: Categorize failure modes before designing harness components. Life-Harness demonstrates that 4 categories cover the majority of deterministic-domain failures.</p></li><li><p><strong>Separation of concerns</strong>: Each lifecycle layer addresses one failure category without interfering with others, enabling clean ablation studies.</p></li><li><p><strong>Cross-model portability</strong>: Harness adaptations targeting environment-level failures transfer across model families, providing leverage independent of model selection.</p></li><li><p><strong>Frozen model assumption</strong>: For deployment contexts where model updates are expensive or impossible, harness adaptation provides a practical improvement pathway.</p></li></ol><hr><h2 id="_6-limitations" tabindex="-1">6. Limitations <a class="header-anchor" href="#_6-limitations" aria-label="Permalink to &quot;6. Limitations&quot;">​</a></h2><ul><li>Evaluated only in deterministic environments (τ-bench, τ²-bench, AgentBench); applicability to non-deterministic or stochastic environments not demonstrated</li><li>BM25-based procedural retrieval (Layer 2) requires existing trajectory database; cold-start scenarios not addressed</li><li>Action realization repair (Layer 3) assumes schema availability; environments without formal schemas require pre-processing</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Xu et al. (2026) Adapting the Interface, Not the Model: Runtime Harness Adaptation for Deterministic LLM Agents. arXiv:2605.22166</li><li>Yao et al. (2023) ReAct: Synergizing Reasoning and Acting in Language Models. ICLR 2023</li><li>Lee et al. (2026) Meta-Harness: End-to-End Optimization of Model Harnesses. arXiv:2603.28052</li><li>Seong et al. (2026) The Last Harness You&#39;ll Ever Build. arXiv:2604.21003</li><li>Zhou et al. (2024) AgentBench: Evaluating LLMs as Agents. ICLR 2024</li><li>Yoran et al. (2026) τ²-bench: Evaluation of Multi-Turn Agent Tasks</li></ul><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paper Concept</th><th>cc-workspace Current State</th><th>Opportunity</th></tr></thead><tbody><tr><td>Environment Contract Layer</td><td>System prompt constraints</td><td>Make tool contract violations explicit in GOTCHAS.md</td></tr><tr><td>Procedural Skill Layer (BM25)</td><td>Manual skill files</td><td>Auto-retrieve relevant past trajectories before session</td></tr><tr><td>Action Realization Layer</td><td>No pre-execution validation</td><td>Add schema validation step in hooks</td></tr><tr><td>Trajectory Regulation Layer</td><td><code>/compact</code> on context saturation</td><td>Add pattern detection for degenerate loop signatures</td></tr><tr><td>Failure taxonomy (4 categories)</td><td>Ad hoc GOTCHAS entries</td><td>Categorize by Life-Harness taxonomy for coverage audit</td></tr><tr><td>Cross-model transfer</td><td>Session-specific settings</td><td>Harness rules should be model-agnostic where possible</td></tr></tbody></table>',50)])])}const p=t(i,[["render",s]]);export{m as __pageData,p as default};
